examples.original_ir:
declare i32 @foo() readnone

define i32 @test(i1 %cond) {
entry:
  %val = call i32 @foo()
  br i1 %cond, label %if.then, label %if.end

if.then:
  ret i32 %val

if.end:
  ret i32 0
}

examples.optimized_ir:
declare i32 @foo() readnone

define i32 @test(i1 %cond) {
entry:
  br i1 %cond, label %if.then, label %if.end

if.then:
  %val = call i32 @foo()
  ret i32 %val

if.end:
  ret i32 0
}
